module RefModule (
    input clk,
    input rst,
    output reg clk_out
);
    reg [2:0] unused_counter;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            unused_counter <= 3'b000;
            clk_out <= 0;
        end else begin
            unused_counter <= unused_counter + 1;
            if (unused_counter == 3'b111) begin
                clk_out <= ~clk_out;
                unused_counter <= 3'b000;
            end
        end
    end
endmodule
